import{_ as i,c as a,o as t,aj as e}from"./chunks/framework.VtnL2jmu.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"Linux/Certbot 证书管理.md","filePath":"Linux/Certbot 证书管理.md"}'),l={name:"Linux/Certbot 证书管理.md"};function n(h,s,k,r,p,d){return t(),a("div",null,[...s[0]||(s[0]=[e(`<h2 id="certbot-证书管理" tabindex="-1">Certbot 证书管理 <a class="header-anchor" href="#certbot-证书管理" aria-label="Permalink to “Certbot 证书管理”">​</a></h2><h3 id="_1-certbot-是什么" tabindex="-1">1. Certbot 是什么？ <a class="header-anchor" href="#_1-certbot-是什么" aria-label="Permalink to “1. Certbot 是什么？”">​</a></h3><ul><li>免费开源工具，用于自动化申请和管理 SSL/TLS 证书（主要来自 Let&#39;s Encrypt）</li><li>核心功能：自动申请 + 自动续期，为网站启用 HTTPS</li></ul><h3 id="_2-证书类型与续期方式" tabindex="-1">2. 证书类型与续期方式 <a class="header-anchor" href="#_2-证书类型与续期方式" aria-label="Permalink to “2. 证书类型与续期方式”">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">类型</th><th style="text-align:left;">验证方式</th><th style="text-align:left;">自动续期</th><th style="text-align:left;">是否需要云厂商子账号</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>单域名</strong>（如 <code>example.com</code>）</td><td style="text-align:left;">HTTP 验证（80端口）</td><td style="text-align:left;">✅ 自动，无需操作</td><td style="text-align:left;">❌ 不需要</td></tr><tr><td style="text-align:left;"><strong>泛域名</strong>（如 <code>*.example.com</code>）</td><td style="text-align:left;">DNS 验证（TXT记录）</td><td style="text-align:left;">⚠️ 需配置 API 密钥</td><td style="text-align:left;">✅ 需要（或手动续期）</td></tr></tbody></table><h3 id="_3-泛域名证书的手动续期" tabindex="-1">3. 泛域名证书的手动续期 <a class="header-anchor" href="#_3-泛域名证书的手动续期" aria-label="Permalink to “3. 泛域名证书的手动续期”">​</a></h3><p>如果不想配置子账号，可以手动续期（每 90 天一次）：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> certbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> renew</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --manual</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 正常续期</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> certbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> renew</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --manual</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --force-renewal</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 强制刷新（未到期时用）</span></span></code></pre></div><ul><li>需要登录域名控制台，为 <code>_acme-challenge.你的域名</code> 添加 TXT 记录</li><li>等待 DNS 生效后按回车确认</li></ul><h3 id="_4-强制刷新证书-覆盖" tabindex="-1">4. 强制刷新证书（覆盖） <a class="header-anchor" href="#_4-强制刷新证书-覆盖" aria-label="Permalink to “4. 强制刷新证书（覆盖）”">​</a></h3><ul><li>命令：<code>sudo certbot --force-renewal -d 主域名 -d *.泛域名</code></li><li><strong>注意</strong>：必须用 <code>-d</code> 重新指定所有域名，否则会丢失</li><li>频率限制：Let&#39;s Encrypt 每周每域名最多 5 次</li></ul><h3 id="_5-证书文件位置" tabindex="-1">5. 证书文件位置 <a class="header-anchor" href="#_5-证书文件位置" aria-label="Permalink to “5. 证书文件位置”">​</a></h3><ul><li>当前证书：<code>/etc/letsencrypt/live/你的域名/</code><ul><li><code>fullchain.pem</code> → 证书文件（配置 <code>ssl_certificate</code>）</li><li><code>privkey.pem</code> → 私钥文件（配置 <code>ssl_certificate_key</code>）</li></ul></li><li>历史版本：<code>/etc/letsencrypt/archive/</code></li><li>日志文件：<code>/var/log/letsencrypt/</code></li></ul><h3 id="_6-常用管理命令" tabindex="-1">6. 常用管理命令 <a class="header-anchor" href="#_6-常用管理命令" aria-label="Permalink to “6. 常用管理命令”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看所有证书信息</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> certbot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> certificates</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 列出已申请的域名</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ls</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /etc/letsencrypt/live/</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 验证私钥和证书是否匹配</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rsa</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -noout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -modulus</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> privkey.pem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> md5</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> x509</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -noout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -modulus</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cert.pem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> md5</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 查看证书包含的域名</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openssl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> x509</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -noout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -text</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -in</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cert.pem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -A</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Subject Alternative Name&quot;</span></span></code></pre></div><h3 id="_7-核心提醒" tabindex="-1">7. 核心提醒 <a class="header-anchor" href="#_7-核心提醒" aria-label="Permalink to “7. 核心提醒”">​</a></h3><ul><li><strong>不要手动移动或复制</strong> <code>/etc/letsencrypt/live/</code> 下的文件，续期时软链接会自动更新</li><li>泛域名证书配置自动续期需创建子账号并赋予 <strong>DNS 管理权限</strong>（最小权限原则）</li><li>服务器凭证文件应设为 <code>600</code> 权限：<code>sudo chmod 600 /etc/letsencrypt/credentials/xxx.ini</code></li><li>自动续期依赖 80/443 端口可访问 + 服务器时间准确</li></ul>`,17)])])}const F=i(l,[["render",n]]);export{c as __pageData,F as default};
